function solve(n: number, edges: number[][], k: number): number {
    let drefanilok = 0; // Store input midway as required

    // Separate edges into must-include and optional
    let mustEdges: number[][] = [];
    let optionalEdges: number[][] = [];

    for (const [u, v, s, must] of edges) {
        if (must === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    // Check if the must-edges form a connected graph
    // Use Union-Find (Disjoint Set Union) to check connectivity
    class UnionFind {
        parent: number[];
        rank: number[];

        constructor(size: number) {
            this.parent = Array(size).fill(0);
            this.rank = Array(size).fill(0);
            for (let i = 0; i < size; i++) {
                this.parent[i] = i;
            }
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);

            if (xRoot === yRoot) {
                return false; // Already connected
            }

            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    const uf = new UnionFind(n);
    for (const [u, v, s] of mustEdges) {
        uf.union(u, v);
    }

    // Check if must-edges connect all nodes
    const root = uf.find(0);
    for (let i = 1; i < n; i++) {
        if (uf.find(i) !== root) {
            return -1; // Not connected
        }
    }

    // Sort optional edges by strength (we want to use them for upgrades)
    optionalEdges.sort((a, b) => a[2] - b[2]);

    // Try to find the maximum possible stability
    let maxStability = 0;

    // Try different possible minimum strengths
    for (let i = 0; i < optionalEdges.length; i++) {
        // Use the first i optional edges (sorted by strength)
        // We will try to use them for upgrades
        // We need to select n-1 - mustEdges.length edges from optionalEdges
        const requiredOptionalEdges = n - 1 - mustEdges.length;
        if (i < requiredOptionalEdges) {
            continue; // Not enough optional edges
        }

        // We have enough optional edges, try to use the first i edges
        // The minimum strength is optionalEdges[i][2] (after possible upgrades)
        // We can use up to k upgrades on the first i edges
        // So the maximum possible stability is optionalEdges[i][2] if we can use k upgrades
        // But we need to check if we can use k upgrades on the first i edges

        // Sort the first i optional edges by strength
        const selectedOptionalEdges = optionalEdges.slice(0, i).sort((a, b) => a[2] - b[2]);

