        if (uf.find(i) !== root) {
            return -1; // Not connected
        }
    }

    // Sort optional edges by strength (we want to use them for upgrades)
    optionalEdges.sort((a, b) => a[2] - b[2]);

    // Try to find the maximum possible stability
    let maxStability = 0;

    // Try different possible minimum strengths
    for (let i = 0; i < optionalEdges.length; i++) {
        // Use the first i optional edges (sorted by strength)
        // We will try to use them for upgrades
        // We need to select n-1 - mustEdges.length edges from optionalEdges
        const requiredOptionalEdges = n - 1 - mustEdges.length;
        if (i < requiredOptionalEdges) {
            continue; // Not enough optional edges
        }

        // We have enough optional edges, try to use the first i edges
        // The minimum strength is optionalEdges[i][2] (after possible upgrades)
        // We can use up to k upgrades on the first i edges
        // So the maximum possible stability is optionalEdges[i][2] if we can use k upgrades
        // But we need to check if we can use k upgrades on the first i edges

        // Sort the first i optional edges by strength
        const selectedOptionalEdges = optionalEdges.slice(0, i).sort((a, b) => a[2] - b[2]);

        // Count how many upgrades we need to use to make the minimum strength as high as possible
        let upgradesUsed = 0;
        for (let j = 0; j < selectedOptionalEdges.length; j++) {
            if (selectedOptionalEdges[j][2] < optionalEdges[i][2]) {
                // We need to upgrade this edge to at least optionalEdges[i][2]
                upgradesUsed++;
                if (upgradesUsed > k) {
                    break;
                }
            }
        }

        if (upgradesUsed <= k) {
            maxStability = Math.max(maxStability, optionalEdges[i][2]);
        }
    }

    return maxStability;
}
